// AnnotationCanvas.js
import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Arrow,
} from 'react-konva';
import './AnnotationCanvas.css';

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool, // 'move', 'bbox', 'polygon', 'polyline', 'point', 'ellipse'
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape,
  // NEW props
  selectedShapeIndex,
  onSelectShape,
  onUpdateAnnotation,
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shapes
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  // ------------------ Setup/Resize the Canvas ------------------
  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        setDims({
          width: containerRef.current.offsetWidth,
          height: containerRef.current.offsetHeight,
        });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // ------------------ Load the Image ------------------
  useEffect(() => {
    if (!fileUrl) return;
    const img = new Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 }); // reset
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // ------------------ Helpers ------------------
  const flattenPoints = (pts) => pts.flatMap((p) => [p.x, p.y]);

  const getGroupPos = (evt) => {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  };

  const isOutsideImage = (ann) => {
    if (!konvaImg) return false;
    // We'll skip the detailed check from before to keep this simpler
    return false;
  };

  // ------------------ BBox Drawing ------------------
  const startBox = (pos) => {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  };
  const updateBox = (pos) => {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  };
  const finalizeBox = () => {
    if (!newBox) return;
    const newAnn = { type: 'bbox', ...newBox, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  };

  // ------------------ Polygon ------------------
  const addPolygonPoint = (pos) => {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  };
  const finalizePolygon = () => {
    if (tempPoints.length >= 3) {
      const newAnn = { type: 'polygon', points: tempPoints, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  };

  // ------------------ Polyline ------------------
  const addPolylinePoint = (pos) => {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  };
  const finalizePolyline = () => {
    if (tempPolyline.length >= 2) {
      const newAnn = { type: 'polyline', points: tempPolyline, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  };

  // ------------------ Point ------------------
  const addPoint = (pos) => {
    const newAnn = { type: 'point', x: pos.x, y: pos.y, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    onFinishShape && onFinishShape();
  };

  // ------------------ Ellipse ------------------
  const startEllipse = (pos) => {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: '',
    });
  };
  const updateEllipse = (pos) => {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  };
  const finalizeEllipse = () => {
    if (!newEllipse) return;
    if (!isOutsideImage(newEllipse)) {
      onAnnotationsChange([...annotations, { ...newEllipse }]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  };

  // ------------------ Mouse Events ------------------
  const handleMouseDown = (evt) => {
    // If user is in 'move' mode, do not start new shapes
    if (selectedTool === 'move') {
      return;
    }
    const pos = getGroupPos(evt);
    if (!pos) return;

    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    } else if (selectedTool === 'polyline') {
      addPolylinePoint(pos);
    } else if (selectedTool === 'point') {
      addPoint(pos);
    } else if (selectedTool === 'ellipse') {
      startEllipse(pos);
    }

    // Deselect if user clicks somewhere else (only if we didn't click a shape)
    // We can do that in handleStageClick below
  };

  const handleMouseMove = (evt) => {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  };

  const handleMouseUp = () => {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  };

  const handleDblClick = () => {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    }
  };

  // -------------- ESC = Cancel shape --------------
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // -------------- Wheel Zoom --------------
  const handleWheel = (evt) => {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  };

  // ------------------ Custom Click: Deselect on empty area ------------------
  const handleStageClick = (e) => {
    // If we clicked on empty space (the stage itself), deselect
    if (e.target === e.target.getStage()) {
      onSelectShape(null);
    }
  };

  // ------------------ Polygon / Polyline Display (No vertex dragging) ------------------
  function NonEditablePolygon({ ann, color, sc }) {
    const firstPt = ann.points[0];
    const secondPt = ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };
    return (
      <Group>
        <Line
          points={flattenPoints(ann.points)}
          fill={color + '55'}
          stroke={color}
          strokeWidth={2 / sc}
          closed
        />
        <Arrow
          points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
          fill={color}
          stroke={color}
          strokeWidth={2 / sc}
          pointerLength={10 / sc}
          pointerWidth={8 / sc}
        />
      </Group>
    );
  }

  function NonEditablePolyline({ ann, color, sc }) {
    const firstPt = ann.points[0];
    const secondPt = ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };
    return (
      <Group>
        <Line
          points={flattenPoints(ann.points)}
          stroke={color}
          strokeWidth={2 / sc}
          closed={false}
        />
        <Arrow
          points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
          fill={color}
          stroke={color}
          strokeWidth={2 / sc}
          pointerLength={10 / sc}
          pointerWidth={8 / sc}
        />
      </Group>
    );
  }

  function NonEditablePoint({ ann, color, sc }) {
    return (
      <Circle
        x={ann.x}
        y={ann.y}
        radius={6 / sc}
        fill={color}
      />
    );
  }

  // ------------------ BBox Resizing Handles ------------------
  // We'll create 4 corner handles for the selected bounding box.
  // Each handle is a small circle that the user can drag.
  // On drag, we recalc x,y,width,height and call `onUpdateAnnotation`.
  const HANDLE_SIZE = 6; // radius
  const handleCornerDragMove = (corner, e, annIndex) => {
    const shape = annotations[annIndex];
    if (!shape || shape.type !== 'bbox') return;

    // Opposite corner = (x + width, y + height)
    const oppX = shape.x + shape.width;
    const oppY = shape.y + shape.height;

    // The new corner position in group coordinates
    const pos = e.target.getPosition();
    const newX1 = corner.includes('left') ? pos.x : shape.x;
    const newY1 = corner.includes('top') ? pos.y : shape.y;
    const newX2 = corner.includes('right') ? pos.x : oppX;
    const newY2 = corner.includes('bottom') ? pos.y : oppY;

    // Convert to standard { x, y, width, height } with width>0, height>0
    const xMin = Math.min(newX1, newX2);
    const yMin = Math.min(newY1, newY2);
    const xMax = Math.max(newX1, newX2);
    const yMax = Math.max(newY1, newY2);

    onUpdateAnnotation(annIndex, {
      x: xMin,
      y: yMin,
      width: xMax - xMin,
      height: yMax - yMin,
    });
  };

  // For code clarity, define a helper that returns the (x, y) of each corner handle
  const getCornerPositions = (bbox) => {
    const { x, y, width, height } = bbox;
    // Return an object with corner name => coordinate
    return {
      topLeft: { x, y },
      topRight: { x: x + width, y },
      bottomLeft: { x, y: y + height },
      bottomRight: { x: x + width, y: y + height },
    };
  };

  // We'll use a small Circle for each handle
  const CornerHandle = ({ cornerName, cx, cy, annIndex }) => {
    return (
      <Circle
        x={cx}
        y={cy}
        radius={HANDLE_SIZE / scale}
        fill="#fff"
        stroke="#000"
        strokeWidth={1 / scale}
        draggable
        onDragMove={(e) => handleCornerDragMove(cornerName, e, annIndex)}
      // Because we do direct onDragMove, we might want to also handle onDragEnd,
      // but in many cases onDragMove is enough for real-time updates.
      />
    );
  };

  // -------------- Rendering --------------
  const fillColor = activeLabelColor + '55';

  return (
    <div
      className="canvas-container"
      ref={containerRef}
      onClick={(e) => {
        // Prevent clicks from trickling up
        // so we rely on Konva's onClick.
        e.stopPropagation();
      }}
    >
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
        onClick={handleStageClick} // for deselect
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'} // allow panning if in move mode
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {/* --- IMAGE --- */}
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* --- Existing Shapes --- */}
            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                // Render bounding box
                const isSelected = i === selectedShapeIndex;
                return (
                  <Group key={i}>
                    <Rect
                      x={ann.x}
                      y={ann.y}
                      width={ann.width}
                      height={ann.height}
                      fill={fillColor}
                      stroke={activeLabelColor}
                      strokeWidth={2 / scale}
                      onClick={(e) => {
                        // Only select if in "move" mode 
                        // (or you can let them select in any mode if you prefer).
                        onSelectShape(i);
                        e.cancelBubble = true;
                      }}
                    />
                    {/* If selected => show corner handles */}
                    {isSelected && (
                      <>
                        {Object.entries(getCornerPositions(ann)).map(
                          ([cornerName, pos]) => (
                            <CornerHandle
                              key={cornerName}
                              cornerName={cornerName}
                              cx={pos.x}
                              cy={pos.y}
                              annIndex={i}
                            />
                          )
                        )}
                      </>
                    )}
                  </Group>
                );
              }
              else if (ann.type === 'polygon') {
                return (
                  <NonEditablePolygon
                    key={i}
                    ann={ann}
                    color={activeLabelColor}
                    sc={scale}
                  />
                );
              } else if (ann.type === 'polyline') {
                return (
                  <NonEditablePolyline
                    key={i}
                    ann={ann}
                    color={activeLabelColor}
                    sc={scale}
                  />
                );
              } else if (ann.type === 'point') {
                return (
                  <NonEditablePoint
                    key={i}
                    ann={ann}
                    color={activeLabelColor}
                    sc={scale}
                  />
                );
              } else if (ann.type === 'ellipse') {
                return (
                  <Ellipse
                    key={i}
                    x={ann.x}
                    y={ann.y}
                    radiusX={ann.radiusX}
                    radiusY={ann.radiusY}
                    rotation={ann.rotation || 0}
                    fill={fillColor}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                  />
                );
              }
              return null;
            })}

            {/* In-progress BBox */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Polygon */}
            {drawingPolygon && tempPoints.length > 1 && selectedTool === 'polygon' && (
              <Line
                points={flattenPoints([...tempPoints, tempPoints[0]])}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed
              />
            )}

            {/* In-progress Polyline */}
            {drawingPolyline && tempPolyline.length > 1 && selectedTool === 'polyline' && (
              <Line
                points={flattenPoints(tempPolyline)}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed={false}
              />
            )}

            {/* In-progress Ellipse */}
            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={0}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}
          </Group>
        </Layer>
      </Stage>
    </div>
  );
}
